module top_module(
    input [7:0] a,
    input [7:0] b,
    output reg [15:0] result
);reg [15:0] temp;
    reg [3:0] obf_i;

    always @(*) begin
        temp = 0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            if (b[obf_i] == 1) begin
                temp = temp + (a << obf_i);
            end
        end
        result = temp;
    end

endmodule
